head.b:skin:
/*------------------------------------------------------------
HADOTI-NEWS PREMIUM ESSENTIAL DESIGN SKIN
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff1e56 0%, #ffac41 50%, #3232ff 100%);
    --dark-bg: #030712;
    --dark-card: #0f172a;
    --light-bg: #f8fafc;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff1e56;
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
}

* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif; background-color: var(--light-bg); color: var(--text-main); transition: all 0.3s ease; }
a { color: inherit; text-decoration: none; }
img { max-width: 100%; height: auto; display: block; border-radius: 8px; }

.container { max-width: 1240px; margin: 0 auto; padding: 0 20px; }

/* Live Bulletin Ticker */
.top-bar { background: #090d16; color: #fff; padding: 12px 0; font-size: 13px; overflow: hidden; }
.ticker-wrap { display: flex; align-items: center; }
.ticker-title { background: var(--primary-gradient); padding: 4px 10px; font-weight: 800; border-radius: 4px; margin-right: 15px; white-space: nowrap; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 25s linear infinite; font-weight: 700; color: #e2e8f0; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Sticky Top Header Area */
header { background: var(--light-card); position: sticky; top: 0; z-index: 999; box-shadow: 0 2px 15px rgba(0,0,0,0.05); padding: 15px 0; }
.header-inner { display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 15px; }

.logo-branding h1 { font-size: 32px; font-weight: 800; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; text-transform: uppercase; }
.logo-sub { display: block; font-size: 10px; font-weight: 700; color: var(--text-muted); letter-spacing: 3px; text-transform: uppercase; }

nav ul { display: flex; gap: 20px; }
nav ul li a { font-weight: 700; font-size: 14.5px; color: var(--text-main); }
nav ul li a:hover { color: var(--accent-color); }

.mode-btn { width: 38px; height: 38px; border-radius: 8px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.05); color: var(--text-main); }

/* Two Column Framework Layout */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 35px; margin-top: 35px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.4fr 1fr; } }

/* Clean News Cards Feed */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 25px; }
@media(min-width: 600px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: 12px; overflow: hidden; box-shadow: 0 10px 25px rgba(0,0,0,0.03); border: 1px solid rgba(0,0,0,0.02); display: flex; flex-direction: column; height: 100%; transition: all 0.3s ease; }
.card:hover { transform: translateY(-4px); box-shadow: 0 20px 35px rgba(0,0,0,0.07); }
.card-thumb { height: 200px; background: #0f172a; position: relative; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; }

.badge { position: absolute; top: 12px; left: 12px; background: var(--primary-gradient); color: #fff; padding: 3px 10px; font-size: 10.5px; font-weight: 800; border-radius: 4px; }
.card-content { padding: 20px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 12.5px; color: var(--text-muted); margin-bottom: 8px; font-weight: 700; }
.card-title { font-size: 18px; font-weight: 800; line-height: 1.4; margin-bottom: 10px; color: var(--text-main); }
.card-title a { color: inherit; }
.card-text { font-size: 13.5px; color: var(--text-muted); line-height: 1.5; margin-bottom: 15px; }
.read-btn { font-weight: 800; font-size: 13.5px; color: var(--accent-color); }

/* Single Article Page Styling */
.post-body-container { background: var(--light-card); padding: 30px; border-radius: 12px; box-shadow: 0 10px 25px rgba(0,0,0,0.03); }
.post-main-title { font-size: 30px; font-weight: 800; line-height: 1.3; margin-bottom: 15px; color: var(--text-main); }
.post-content-inner { font-size: 16.5px; line-height: 1.8; color: var(--text-main); }
.post-content-inner p { margin-bottom: 18px; }

/* Sidebar Widgets Styling */
.sidebar-pane { display: flex; flex-direction: column; gap: 30px; }
.block-widget { background: var(--light-card); padding: 22px; border-radius: 12px; box-shadow: 0 10px 25px rgba(0,0,0,0.03); border: 1px solid rgba(0,0,0,0.02); }
.block-title { font-size: 15px; font-weight: 800; text-transform: uppercase; margin-bottom: 15px; padding-bottom: 8px; color: var(--text-main); border-bottom: 2px solid rgba(0,0,0,0.04); }

.search-input-group form { display: flex; gap: 6px; }
.search-field { flex-grow: 1; padding: 10px 12px; border: 1px solid rgba(0,0,0,0.08); border-radius: 6px; background: var(--light-bg); color: var(--text-main); outline: none; }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 15px; border-radius: 6px; font-weight: 800; cursor: pointer; }

.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 6px; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 5px 12px; font-size: 13px; font-weight: 700; border-radius: 6px; }

/* Corporate Minimal Footer */
footer { background: #02050b; color: #94a3b8; padding: 40px 0; margin-top: 60px; text-align: center; font-size: 14px; font-weight: 700; border-top: 2px solid var(--accent-color); }
footer a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 800; }

body.script:
//
// Dark/Light Mode Interchanger Logic 
const toggleEngineBtn = document.getElementById('dark-mode-engine-btn');
const themeIconSymbol = toggleEngineBtn.querySelector('i');

toggleEngineBtn.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        themeIconSymbol.className = 'fas fa-sun';
    } else {
        themeIconSymbol.className = 'fas fa-moon';
    }
});
//
